import json

# Mapping atomic numbers 1..26 to element symbols
NUM_TO_SYM = {
    1: 'H',  2: 'He', 3: 'Li', 4: 'Be', 5: 'B',  6: 'C',  7: 'N',  8: 'O',  9: 'F', 10: 'Ne',
   11: 'Na', 12: 'Mg',13: 'Al',14: 'Si',15: 'P', 16: 'S', 17: 'Cl',18: 'Ar',19: 'K', 20: 'Ca',
   21: 'Sc',22: 'Ti',23: 'V', 24: 'Cr',25: 'Mn',26: 'Fe'
}
SYM_TO_NUM = {v: k for k, v in NUM_TO_SYM.items()}

# 1. Forward Function
def transform_grid(grid):
    """Encode a 1D string: letters -> element symbols + case marker; others unchanged."""
    if grid is None:
        return None
    if not isinstance(grid, str):
        raise TypeError('transform_grid expects a string')
    out_parts = []
    for ch in grid:
        # Only ASCII English letters A-Z or a-z are encoded
        if ('A' <= ch <= 'Z') or ('a' <= ch <= 'z'):
            p = ord(ch.upper()) - ord('A') + 1  # 1..26
            sym = NUM_TO_SYM[p]
            marker = '^' if ('A' <= ch <= 'Z') else '_'
            out_parts.append(sym + marker)
        else:
            out_parts.append(ch)
    return ''.join(out_parts)

# 2. Inverse Function
def inverse_transform_grid(grid):
    """Decode a string produced by transform_grid back to the original."""
    if grid is None:
        return None
    if not isinstance(grid, str):
        raise TypeError('inverse_transform_grid expects a string')
    i = 0
    L = len(grid)
    out_chars = []
    while i < L:
        ch = grid[i]
        # If an uppercase ASCII letter appears it's the start of an encoded symbol
        if 'A' <= ch <= 'Z':
            # Parse 1- or 2-letter element symbol (second letter, if present, must be lowercase)
            if i + 1 < L and 'a' <= grid[i + 1] <= 'z':
                sym = grid[i:i+2]
                j = i + 2
            else:
                sym = grid[i]
                j = i + 1
            # Next character must be the case marker
            if j >= L:
                raise ValueError(f"Malformed encoded string: missing case marker after symbol at pos {i}")
            marker = grid[j]
            if marker not in ('^', '_'):
                raise ValueError(f"Malformed encoded string: expected '^' or '_' at pos {j}, got {marker!r}")
            if sym not in SYM_TO_NUM:
                raise ValueError(f"Unknown element symbol {sym!r} at pos {i}")
            p = SYM_TO_NUM[sym]
            letter = chr(ord('A') + p - 1)
            letter = letter if marker == '^' else letter.lower()
            out_chars.append(letter)
            i = j + 1
        else:
            # Non-start characters are copied verbatim
            out_chars.append(ch)
            i += 1
    return ''.join(out_chars)

# 3. Examples and Data
examples_inputs = [
    'Ab!c',                      # fragment from the prompt
    'Hello, World!',             # mixed-case with punctuation
    '',                          # empty
    'Z',                         # single uppercase
