# 6. Final Output (JSON printed by this script when executed)
print(json.dumps({
    'examples': examples,
    'question_plaintext': question_plaintext,
    'answer_ciphertext': answer_ciphertext
}, ensure_ascii=False))

import json

# 1. Forward Function
def transform_grid(grid):
    """Apply the specified bijective per-character substitution to a 3D grid.
    grid: list of layers; each layer is a list of row-strings (rows in a layer must have equal length).
    Returns a new grid (same shape) with characters substituted.
    """
    if not isinstance(grid, list):
        raise TypeError('grid must be a list of layers')
    result = []
    for layer in grid:
        if not isinstance(layer, list):
            raise TypeError('each layer must be a list of row-strings')
        new_layer = []
        for row in layer:
            if not isinstance(row, str):
                raise TypeError('each row must be a string')
            out_chars = []
            for ch in row:
                # Uppercase Atbash
                if 'A' <= ch <= 'Z':
                    out_chars.append(chr(ord('Z') - (ord(ch) - ord('A'))))
                # Lowercase Atbash
                elif 'a' <= ch <= 'z':
                    out_chars.append(chr(ord('z') - (ord(ch) - ord('a'))))
                # 9's-complement for digits
                elif '0' <= ch <= '9':
                    out_chars.append(chr(ord('9') - (ord(ch) - ord('0'))))
                # Paired punctuation swaps
                elif ch == '(':
                    out_chars.append(')')
                elif ch == ')':
                    out_chars.append('(')
                elif ch == '[':
                    out_chars.append(']')
                elif ch == ']':
                    out_chars.append('[')
                elif ch == '{':
                    out_chars.append('}')
                elif ch == '}':
                    out_chars.append('{')
                elif ch == '<':
                    out_chars.append('>')
                elif ch == '>':
                    out_chars.append('<')
                elif ch == '/':
                    # return backslash via chr(92) to avoid literal backslash issues
                    out_chars.append(chr(92))
                elif ord(ch) == 92:  # backslash
                    out_chars.append('/')
                # Space unchanged
                elif ch == ' ':
                    out_chars.append(' ')
                # Identity for everything else
                else:
                    out_chars.append(ch)
            new_layer.append(''.join(out_chars))
        result.append(new_layer)
    return result

# 2. Inverse Function (same operation since mapping is involutive)
def inverse_transform_grid(grid):
    """Inverse is identical to forward since mapping is self-inverse."""
    return transform_grid(grid)

