import json

def transform_grid(grid):
    # Handle empty or zero-width grids
    if not grid or not grid[0]:
        return [row[:] for row in grid]
    N = len(grid)
    M = len(grid[0])
    # Step 1: rotate each row right by s_i
    rows = []
    for row in grid:
        s = sum(ord(c) for c in row) % M if M else 0
        if s:
            rows.append(row[-s:] + row[:-s])
        else:
            rows.append(row[:])
    # Step 2: rotate each column down by t_j
    result = [r[:] for r in rows]
    for j in range(M):
        t = sum(ord(rows[i][j]) for i in range(N)) % N if N else 0
        if t:
            col = [rows[(i - t) % N][j] for i in range(N)]
        else:
            col = [rows[i][j] for i in range(N)]
        for i in range(N):
            result[i][j] = col[i]
    return result

def inverse_transform_grid(grid):
    # Handle empty or zero-width grids
    if not grid or not grid[0]:
        return [row[:] for row in grid]
    N = len(grid)
    M = len(grid[0])
    # Step 1 inverse: rotate each column up by t_j
    cols = [row[:] for row in grid]
    for j in range(M):
        t = sum(ord(grid[i][j]) for i in range(N)) % N if N else 0
        if t:
            col = [grid[(i + t) % N][j] for i in range(N)]
        else:
            col = [grid[i][j] for i in range(N)]
        for i in range(N):
            cols[i][j] = col[i]
    # Step 2 inverse: rotate each row left by s_i
    result = []
    for row in cols:
        s = sum(ord(c) for c in row) % M if M else 0
        if s:
            result.append(row[s:] + row[:s])
        else:
            result.append(row[:])
    return result

