import json

# 1. Forward Function
def transform_grid(grid):
    N = len(grid)
    if N == 0:
        return []
    # Step 1: Axis permutation
    M = [[[None]*N for _ in range(N)] for _ in range(N)]
    for z in range(N):
        for y in range(N):
            for x in range(N):
                M[x][z][N-1-y] = grid[z][y][x]
    # Step 2: Layer row shift
    output = [[[None]*N for _ in range(N)] for _ in range(N)]
    for k in range(N):
        for j in range(N):
            for i in range(N):
                output[k][j][(i+k) % N] = M[k][j][i]
    return output

# 2. Inverse Function
def inverse_transform_grid(grid):
    N = len(grid)
    if N == 0:
        return []
    # Step 1: Undo row shift
    M = [[[None]*N for _ in range(N)] for _ in range(N)]
    for k in range(N):
        for j in range(N):
            for i in range(N):
                M[k][j][i] = grid[k][j][(i+k) % N]
    # Step 2: Invert axis permutation
    original = [[[None]*N for _ in range(N)] for _ in range(N)]
    for k in range(N):
        for j in range(N):
            for i in range(N):
                z = j; x = k; y = N-1-i
                original[z][y][x] = M[k][j][i]
    return original

