atomic_to_symbol = {1:"H",2:"He",3:"Li",4:"Be",5:"B",6:"C",7:"N",8:"O",9:"F",10:"Ne",11:"Na",12:"Mg",13:"Al",14:"Si",15:"P",16:"S",17:"Cl",18:"Ar",19:"K",20:"Ca",21:"Sc",22:"Ti",23:"V",24:"Cr",25:"Mn",26:"Fe"}
symbol_to_atomic = {v:k for k,v in atomic_to_symbol.items()}

def transform_grid(grid):
    result = []
    for s in grid:
        out = ""
        for ch in s:
            num = ord(ch) - 64
            if num < 1 or num > 26:
                raise ValueError("Invalid letter: %s" % ch)
            out += atomic_to_symbol[num]
        result.append(out)
    return result

def inverse_transform_grid(grid):
    result = []
    for s in grid:
        out = ""
        i = 0
        while i < len(s):
            if i+1 < len(s) and s[i:i+2] in symbol_to_atomic:
                sym = s[i:i+2]
                i += 2
            elif s[i] in symbol_to_atomic:
                sym = s[i]
                i += 1
            else:
                raise ValueError("Invalid symbol at pos %d in %s" % (i, s))
            num = symbol_to_atomic[sym]
            if num < 1 or num > 26:
                raise ValueError("Atomic number out of range: %d" % num)
            out += chr(num + 64)
        result.append(out)
    return result

