# Mirror mapping initialization
_MIRROR_MAP = {}
import string
for i, c in enumerate(string.ascii_uppercase):
    _MIRROR_MAP[c] = string.ascii_uppercase[-(i+1)]
for i, c in enumerate(string.digits):
    _MIRROR_MAP[c] = string.digits[-(i+1)]
pairs = [('(',')'),('[',']'),('{','}'),('<','>')]
for a,b in pairs:
    _MIRROR_MAP[a] = b
    _MIRROR_MAP[b] = a

def transform_grid(grid):
    # Step 1: rotate 180° by reversing rows and each row's characters
    rotated = [row[::-1] for row in grid[::-1]]
    # Step 2: apply mirror mapping to each character
    return [''.join(_MIRROR_MAP.get(ch, ch) for ch in row) for row in rotated]

def inverse_transform_grid(grid):
    # Due to involution of both steps, same as transform_grid
    return transform_grid(grid)

