import json

def atbash_char(c):
    if 'A' <= c <= 'Z':
        return chr(ord('Z') - (ord(c) - ord('A')))
    if 'a' <= c <= 'z':
        return chr(ord('z') - (ord(c) - ord('a')))
    return c

# 1. Forward Function
def transform_grid(grid):
    N = len(grid)
    if N == 0:
        return []
    result = [[[ '' for _ in range(N)] for _ in range(N)] for _ in range(N)]
    for i in range(N):
        for j in range(N):
            for k in range(N):
                i2, j2, k2 = k, j, N - 1 - i
                result[i2][j2][k2] = atbash_char(grid[i][j][k])
    return result

# 2. Inverse Function
def inverse_transform_grid(grid):
    N = len(grid)
    if N == 0:
        return []
    original = [[[ '' for _ in range(N)] for _ in range(N)] for _ in range(N)]
    for i2 in range(N):
        for j2 in range(N):
            for k2 in range(N):
                c = atbash_char(grid[i2][j2][k2])
                i, j, k = N - 1 - k2, j2, i2
                original[i][j][k] = c
    return original

