import json

# Define the complete character mappings for QWERTY and Dvorak layouts.
# This includes all 47 common keys, both unshifted and shifted states.
QWERTY_CHARS = (
    "`1234567890-=qwertyuiop[]\\asdfghjkl;'zxcvbnm,./"  # Unshifted
    "~!@#$%^&*()_+QWERTYUIOP{}|ASDFGHJKL:\"ZXCVBNM<>?"   # Shifted
)
DVORAK_CHARS = (
    "`1234567890[]',.pyfgcrl/=\\aoeuidhtns-`;qjkxbmwvz" # Unshifted
    "~!@#$%^&*(){}\"<>PYFGCRL?+AOEUIDHTNS_:QJKXBMWVZ"  # Shifted
)

# Create efficient translation tables for both forward and inverse transformations.
QWERTY_TO_DVORAK_TABLE = str.maketrans(QWERTY_CHARS, DVORAK_CHARS)
DVORAK_TO_QWERTY_TABLE = str.maketrans(DVORAK_CHARS, QWERTY_CHARS)

def _apply_translation(grid, translation_table):
    """Helper function to apply a translation table to a 2D grid of characters."""
    if not isinstance(grid, list):
        return grid # Handle non-list inputs gracefully

    transformed_grid = []
    for row in grid:
        if not isinstance(row, list):
            transformed_grid.append(row) # Pass through non-list rows
            continue
        # Join row into a string, translate, then split back to a list of chars
        row_as_string = "".join(row)
        translated_row = list(row_as_string.translate(translation_table))
        transformed_grid.append(translated_row)
    return transformed_grid

# 1. Forward Function: QWERTY -> Dvorak
def transform_grid(grid):
    """Transforms a grid of characters from QWERTY to Dvorak layout."""
    return _apply_translation(grid, QWERTY_TO_DVORAK_TABLE)

# 2. Inverse Function: Dvorak -> QWERTY
def inverse_transform_grid(grid):
    """Transforms a grid of characters from Dvorak back to QWERTY layout."""
    return _apply_translation(grid, DVORAK_TO_QWERTY_TABLE)

