import json

# --- Cipher Implementations ---

def _atbash(char):
    """Applies the Atbash cipher (A<->Z). It is its own inverse."""
    val = ord(char) - ord('A')
    return chr(ord('A') + (25 - val))

def _rot13(char):
    """Applies the ROT13 cipher. It is its own inverse."""
    val = ord(char) - ord('A')
    return chr(ord('A') + (val + 13) % 26)

def _affine_forward(char):
    """Applies the Affine cipher C = (5P + 8) mod 26."""
    p = ord(char) - ord('A')
    c = (5 * p + 8) % 26
    return chr(ord('A') + c)

def _affine_inverse(char):
    """Applies the inverse Affine cipher P = 21(C - 8) mod 26."""
    c = ord(char) - ord('A')
    # 21 is the modular multiplicative inverse of 5 mod 26.
    # Python's % operator handles negative results correctly for modular arithmetic.
    p = (21 * (c - 8)) % 26
    return chr(ord('A') + p)

# --- Core Grid Processing Logic ---

def _process_grid(grid, d_cipher, h_cipher, w_cipher):
    """Generic grid processor that applies ciphers based on dominant axis."""
    if not isinstance(grid, list) or not grid:
        return []

    new_grid = []
    for d, plane in enumerate(grid):
        if not isinstance(plane, list):
            # Handle malformed input
            raise TypeError(f"Grid plane at depth {d} is not a list.")
        new_plane = []
        for h, row in enumerate(plane):
            if not isinstance(row, list):
                raise TypeError(f"Grid row at (d={d}, h={h}) is not a list.")
            new_row = []
            for w, char in enumerate(row):
                # Determine dominant axis with tie-breaking D > H > W
                if d >= h and d >= w:  # Depth dominant
                    transformed_char = d_cipher(char)
                elif h > d and h >= w:  # Height dominant
                    transformed_char = h_cipher(char)
                else:  # Width dominant (w > d and w > h)
                    transformed_char = w_cipher(char)
                new_row.append(transformed_char)
            new_plane.append(new_row)
        new_grid.append(new_plane)
    return new_grid

# 1. Forward Function
def transform_grid(grid):
    """Transforms the grid using the forward 'Axis-Dominant' rule."""
    return _process_grid(grid, _atbash, _rot13, _affine_forward)

# 2. Inverse Function
def inverse_transform_grid(grid):
    """Reverses the grid transformation."""
    # Atbash and ROT13 are their own inverses
    return _process_grid(grid, _atbash, _rot13, _affine_inverse)

