import json

def transform_grid(grid: str) -> str:
    """
    Performs the forward transformation:
    1. De-interleaves the string into even and odd indexed characters.
    2. Reverses the odd-indexed character string.
    3. Concatenates the even-indexed string with the reversed odd-indexed string.
    """
    if not isinstance(grid, str):
        raise TypeError("Input must be a string.")
    if len(grid) <= 1:
        return grid

    s_even = grid[0::2]
    s_odd = grid[1::2]

    return s_even + s_odd[::-1]

def inverse_transform_grid(grid: str) -> str:
    """
    Reverses the transformation to reconstruct the original string.
    """
    if not isinstance(grid, str):
        raise TypeError("Input must be a string.")
    if len(grid) <= 1:
        return grid

    L = len(grid)
    # Calculate split point using integer arithmetic for ceil(L/2)
    len_even = (L + 1) // 2

    s_even = grid[:len_even]
    reversed_s_odd = grid[len_even:]
    s_odd = reversed_s_odd[::-1]

    original_chars = []
    # Interleave s_even and s_odd
    for i in range(len(s_odd)):
        original_chars.append(s_even[i])
        original_chars.append(s_odd[i])

    # Append the last character of s_even if the original length was odd
    if len(s_even) > len(s_odd):
        original_chars.append(s_even[-1])

    return "".join(original_chars)

