# 1. Forward Function
def transform_grid(grid: str) -> str:
    """
    Encodes a string by converting each character's ASCII value to its
    binary-reflected Gray code equivalent.
    """
    if not isinstance(grid, str):
        raise TypeError("Input must be a string.")

    return "".join([chr(ord(char) ^ (ord(char) >> 1)) for char in grid])

# 2. Inverse Function
def inverse_transform_grid(grid: str) -> str:
    """
    Decodes a string from Gray code back to the original ASCII values.
    """
    if not isinstance(grid, str):
        raise TypeError("Input must be a string.")

    def gray_to_binary(g: int) -> int:
        """Converts an 8-bit Gray code value back to binary."""
        b = g
        # The inverse operation can be parallelized for efficiency.
        # For an 8-bit number, we only need to shift up to 4 bits.
        b ^= (b >> 1)
        b ^= (b >> 2)
        b ^= (b >> 4)
        return b

    return "".join([chr(gray_to_binary(ord(char))) for char in grid])

