# 1. Forward Function
def transform_grid(grid):
    M = len(grid)
    if M == 0:
        return []
    N = len(grid[0])
    # Row-wise rotation
    row_shifted = []
    for i, row in enumerate(grid):
        k = i % N if N else 0
        if k:
            row_shifted.append(row[-k:] + row[:-k])
        else:
            row_shifted.append(list(row))
    # Column-wise rotation
    result = [ [None]*N for _ in range(M) ]
    for j in range(N):
        k = j % M
        col = [row_shifted[i][j] for i in range(M)]
        if k:
            new_col = col[-k:] + col[:-k]
        else:
            new_col = col
        for i in range(M):
            result[i][j] = new_col[i]
    return result

# 2. Inverse Function
def inverse_transform_grid(grid):
    M = len(grid)
    if M == 0:
        return []
    N = len(grid[0])
    # Column-wise inverse rotation (upwards)
    col_unshifted = [ [None]*N for _ in range(M) ]
    for j in range(N):
        k = j % M
        col = [grid[i][j] for i in range(M)]
        if k:
            new_col = col[k:] + col[:k]
        else:
            new_col = col
        for i in range(M):
            col_unshifted[i][j] = new_col[i]
    # Row-wise inverse rotation (leftwards)
    result = []
    for i, row in enumerate(col_unshifted):
        k = i % N if N else 0
        if k:
            result.append(row[k:] + row[:k])
        else:
            result.append(list(row))
    return result

