import json

# 1. Forward Function
def transform_grid(grid):
    # grid: list of L layers, each layer is a list of H rows, each row is a sequence of W characters (string or list)
    L = len(grid)
    if L == 0:
        return []

    # Validate structure and determine H
    if not all(isinstance(layer, list) for layer in grid):
        raise TypeError('Each layer must be a list of rows')
    H = len(grid[0])
    for layer in grid:
        if len(layer) != H:
            raise ValueError('All layers must have the same number of rows (H)')

    # If there are no rows, return empty layers preserving count
    if H == 0:
        return [ [] for _ in range(L) ]

    # Determine if rows are strings everywhere (preserve this representation on output)
    all_rows_are_str = all(isinstance(row, str) for layer in grid for row in layer)

    # Determine W and validate
    first_row = grid[0][0]
    W = len(first_row)
    for layer in grid:
        for row in layer:
            if len(row) != W:
                raise ValueError('All rows must have the same number of columns (W)')

    # Convert to mutable char matrix: chars[z][y][x]
    chars = []
    for layer in grid:
        layer_chars = []
        for row in layer:
            # list(row) works for both strings and lists
            layer_chars.append(list(row))
        chars.append(layer_chars)

    # Per-layer shear -> intermediate (in-place conceptually but we build a new structure)
    intermediate = [ [ [None] * W for _ in range(H) ] for _ in range(L) ]
    for z in range(L):
        for y in range(H):
            for x in range(W):
                ch = chars[z][y][x]
                y1 = (y + z) % H
                x1 = (x + z) % W
                intermediate[z][y1][x1] = ch

    # Depth reversal
    reversed_layers = intermediate[::-1]

    # Reconstruct output keeping row representation as strings if input used strings everywhere
    result = []
    for layer in reversed_layers:
        if len(layer) == 0:
            result.append([])
            continue
        if all_rows_are_str:
            result.append([''.join(row) for row in layer])
        else:
            # return lists of characters
            result.append([list(row) for row in layer])
    return result

# 2. Inverse Function
def inverse_transform_grid(grid):
    L = len(grid)
    if L == 0:
        return []

    if not all(isinstance(layer, list) for layer in grid):
        raise TypeError('Each layer must be a list of rows')
    H = len(grid[0])
    for layer in grid:
        if len(layer) != H:
            raise ValueError('All layers must have the same number of rows (H)')

    if H == 0:
        return [ [] for _ in range(L) ]

    all_rows_are_str = all(isinstance(row, str) for layer in grid for row in layer)

    first_row = grid[0][0]
    W = len(first_row)
    for layer in grid:
        for row in layer:
            if len(row) != W:
                raise ValueError('All rows must have the same number of columns (W)')

    # Step 1: Depth unreversal
    depth_unreversed = grid[::-1]

    # Convert to char lists
    chars = []
    for layer in depth_unreversed:
        layer_chars = []
        for row in layer:
            layer_chars.append(list(row))
        chars.append(layer_chars)

    # Prepare original-shaped container
    original_chars = [ [ [None] * W for _ in range(H) ] for _ in range(L) ]

    # Undo per-layer shear
    for z in range(L):
        for y1 in range(H):
            for x1 in range(W):
                ch = chars[z][y1][x1]
                y = (y1 - z) % H
                x = (x1 - z) % W
                original_chars[z][y][x] = ch

    # Reconstruct preserving row type
    result = []
    for layer in original_chars:
        if len(layer) == 0:
            result.append([])
            continue
        if all_rows_are_str:
            result.append([''.join(row) for row in layer])
        else:
            result.append([list(row) for row in layer])
    return result

