# NATO phonetic list (first-letter capitalization as required)
NATO = [
    'Alpha','Bravo','Charlie','Delta','Echo','Foxtrot','Golf','Hotel','India',
    'Juliett','Kilo','Lima','Mike','November','Oscar','Papa','Quebec','Romeo',
    'Sierra','Tango','Uniform','Victor','Whiskey','Xray','Yankee','Zulu'
]

DIGITS = ['Zero','One','Two','Three','Four','Five','Six','Seven','Eight','Nine']

# Punctuation mapping char -> name
PUNCT_MAP = {
    ' ': 'SPACE',
    '.': 'Period', ',': 'Comma', '?': 'Question', '!': 'Exclamation',
    ':': 'Colon', ';': 'Semicolon', '-': 'Hyphen', '"': 'Quote', "'": 'Apostrophe',
    '/': 'Slash', '\\': 'Backslash', '@': 'At', '#': 'Hash', '$': 'Dollar',
    '%': 'Percent', '&': 'Ampersand', '*': 'Asterisk', '(': 'LParen', ')': 'RParen',
    '[': 'LBracket', ']': 'RBracket', '{': 'LBrace', '}': 'RBrace', '|': 'Pipe',
    '<': 'LT', '>': 'GT', '+': 'Plus', '=': 'Equal'
}

# Build reverse maps for decoding
PUNCT_NAME_TO_CHAR = {}
for k, v in PUNCT_MAP.items():
    if v == 'SPACE':
        PUNCT_NAME_TO_CHAR[v] = ' '
    else:
        PUNCT_NAME_TO_CHAR[v] = k

DIGIT_NAME_TO_CHAR = {name: str(i) for i, name in enumerate(DIGITS)}
NATO_NAME_TO_UPPER = {name: chr(i + 65) for i, name in enumerate(NATO)}
NATO_NAME_TO_LOWER = {name: chr(i + 97) for i, name in enumerate(NATO)}

# 1. Forward Function
def transform_grid(grid):
    """
    Encode a string into bracketed tokens joined by '|'.
    """
    if grid == '':
        return ''
    tokens = []
    for ch in grid:
        # Uppercase letters
        if 'A' <= ch <= 'Z':
            name = NATO[ord(ch) - 65]
            tokens.append(f"[UPPER:{name}]")
            continue
        # Lowercase letters
        if 'a' <= ch <= 'z':
            name = NATO[ord(ch) - 97]
            tokens.append(f"[LOWER:{name}]")
            continue
        # Digits 0-9
        if ch in '0123456789':
            name = DIGITS[ord(ch) - 48]
            tokens.append(f"[DIGIT:{name}]")
            continue
        # Space and defined punctuation
        if ch in PUNCT_MAP:
            # space has a special token [SPACE]
            if ch == ' ':
                tokens.append('[SPACE]')
            else:
                tokens.append(f"[PUNCT:{PUNCT_MAP[ch]}]")
            continue
        # Fallback: encode by Unicode codepoint hex (uppercase, no U+)
        code = format(ord(ch), 'X')
        tokens.append(f"[UNICODE:{code}]")
    return '|'.join(tokens)

# 2. Inverse Function
def inverse_transform_grid(grid):
    """
    Decode a token string produced by transform_grid back to the original string.
    Raises ValueError on invalid token.
    """
    if grid == '':
        return ''
    parts = grid.split('|')
    chars = []
    for tok in parts:
        if not (tok.startswith('[') and tok.endswith(']')):
            raise ValueError(f"Invalid token format: {tok!r}")
        inner = tok[1:-1]
        # [SPACE]
        if inner == 'SPACE':
            chars.append(' ')
            continue
        # Classes like UPPER:Name, LOWER:Name, DIGIT:Name, PUNCT:Name, UNICODE:HEX
        if ':' not in inner:
            raise ValueError(f"Invalid token content: {inner!r}")
        cls, val = inner.split(':', 1)
        if cls == 'UPPER':
            if val not in NATO_NAME_TO_UPPER:
                raise ValueError(f"Unknown UPPER name: {val!r}")
            chars.append(NATO_NAME_TO_UPPER[val])
            continue
        if cls == 'LOWER':
            if val not in NATO_NAME_TO_LOWER:
                raise ValueError(f"Unknown LOWER name: {val!r}")
            chars.append(NATO_NAME_TO_LOWER[val])
            continue
        if cls == 'DIGIT':
            if val not in DIGIT_NAME_TO_CHAR:
                raise ValueError(f"Unknown DIGIT name: {val!r}")
            chars.append(DIGIT_NAME_TO_CHAR[val])
            continue
        if cls == 'PUNCT':
            if val not in PUNCT_NAME_TO_CHAR:
                raise ValueError(f"Unknown PUNCT name: {val!r}")
            chars.append(PUNCT_NAME_TO_CHAR[val])
            continue
        if cls == 'UNICODE':
            # parse hex
            try:
                code = int(val, 16)
            except Exception:
                raise ValueError(f"Invalid UNICODE hex: {val!r}")
            chars.append(chr(code))
            continue
        raise ValueError(f"Unknown token class: {cls!r}")
    return ''.join(chars)

