    return [
        [
            # On even layers (z % 2 == 0), swap chars; otherwise, keep original.
            [_SWAP_MAP.get(char, char) for char in row] if z % 2 == 0 else list(row)
            for row in (layer if isinstance(layer, list) else [])
        ]
        for z, layer in enumerate(grid)
    ]

