# Define the working character set
_WORKING_CHAR_SET = [chr(i) for i in range(32, 127)]
_SET_SIZE = len(_WORKING_CHAR_SET) # 95

# Create a mapping for quick lookup
_CHAR_TO_IDX = {char: i for i, char in enumerate(_WORKING_CHAR_SET)}

def _transform_char(char):
    """
    Transforms a single character based on the symmetrical opposite index rule.
    """
    if char in _CHAR_TO_IDX:
        idx = _CHAR_TO_IDX[char]
        opposite_idx = (_SET_SIZE - 1 - idx)
        return _WORKING_CHAR_SET[opposite_idx]
    else:
        # Character not in working set, remains unchanged
        return char

def transform_grid(grid):
    """
    Encodes a 2D grid of characters according to the specified rule.
    Handles empty grids, empty rows, and non-working-set characters.
    """
    if not isinstance(grid, list):
        raise TypeError("Input grid must be a list of lists.")

    transformed_grid = []
    for row in grid:
        if not isinstance(row, list):
            raise TypeError("Each row in the grid must be a list.")
        transformed_row = [_transform_char(char) for char in row]
        transformed_grid.append(transformed_row)
    return transformed_grid

def inverse_transform_grid(grid):
    """
    Decodes a 2D grid of characters by applying the exact same transformation rule,
    as the rule is self-inverse.
    """
    return transform_grid(grid)

