import json

# Helper function for Atbash cipher
def _atbash_char(char):
    if 'A' <= char <= 'Z':
        return chr(ord('A') + ord('Z') - ord(char))
    elif 'a' <= char <= 'z':
        return chr(ord('a') + ord('z') - ord(char))
    return char

# 1. Forward Function
def transform_grid(grid):
    transformed_grid = []
    for z_idx, layer in enumerate(grid):
        transformed_layer = []
        for y_idx, row in enumerate(layer):
            transformed_row = []
            for x_idx, char in enumerate(row):
                transformed_char = char
                # Rule 1: Even layer (z), uppercase char
                if z_idx % 2 == 0 and 'A' <= char <= 'Z':
                    transformed_char = _atbash_char(char)
                # Rule 2: Odd layer (z), lowercase char
                elif z_idx % 2 != 0 and 'a' <= char <= 'z':
                    transformed_char = _atbash_char(char)
                # Rule 3: Otherwise, char remains unchanged
                transformed_row.append(transformed_char)
            transformed_layer.append(transformed_row)
        transformed_grid.append(transformed_layer)
    return transformed_grid

# 2. Inverse Function
# Since the Atbash cipher is its own inverse, and the conditions for
# transformation are identical for both forward and inverse operations,
# the inverse function applies the exact same logic as the forward function.
def inverse_transform_grid(grid):
    original_grid = []
    for z_idx, layer in enumerate(grid):
        original_layer = []
        for y_idx, row in enumerate(layer):
            original_row = []
            for x_idx, char in enumerate(row):
                original_char = char
                # Rule 1: Even layer (z), uppercase char
                if z_idx % 2 == 0 and 'A' <= char <= 'Z':
                    original_char = _atbash_char(char)
                # Rule 2: Odd layer (z), lowercase char
                elif z_idx % 2 != 0 and 'a' <= char <= 'z':
                    original_char = _atbash_char(char)
                # Rule 3: Otherwise, char remains unchanged
                original_row.append(original_char)
            original_layer.append(original_row)
        original_grid.append(original_layer)
    return original_grid

