# 1. Forward Function
def transform_grid(grid):
    'Transform string using NATO code tags.'
    nato_upper = {
        'A':'Alpha','B':'Bravo','C':'Charlie','D':'Delta','E':'Echo',
        'F':'Foxtrot','G':'Golf','H':'Hotel','I':'India','J':'Juliett',
        'K':'Kilo','L':'Lima','M':'Mike','N':'November','O':'Oscar',
        'P':'Papa','Q':'Quebec','R':'Romeo','S':'Sierra','T':'Tango',
        'U':'Uniform','V':'Victor','W':'Whiskey','X':'X-ray','Y':'Yankee','Z':'Zulu'
    }
    nato_lower = {k.lower():v.lower() for k,v in nato_upper.items()}
    result = []
    for c in grid:
        if c in nato_upper:
            result.append(f'<NATO:{nato_upper[c]}>' )
        elif c in nato_lower:
            result.append(f'<nato:{nato_lower[c]}>' )
        else:
            result.append(c)
    return ''.join(result)

# 2. Inverse Function
def inverse_transform_grid(grid):
    'Revert NATO tags back to original string.'
    nato_upper = {
        'Alpha':'A','Bravo':'B','Charlie':'C','Delta':'D','Echo':'E',
        'Foxtrot':'F','Golf':'G','Hotel':'H','India':'I','Juliett':'J',
        'Kilo':'K','Lima':'L','Mike':'M','November':'N','Oscar':'O',
        'Papa':'P','Quebec':'Q','Romeo':'R','Sierra':'S','Tango':'T',
        'Uniform':'U','Victor':'V','Whiskey':'W','X-ray':'X','Yankee':'Y','Zulu':'Z'
    }
    nato_lower = {k.lower():v.lower() for k,v in nato_upper.items()}
    result = []
    i = 0
    n = len(grid)
    while i < n:
        if grid[i] == '<':
            j = grid.find('>', i+1)
            if j == -1:
                result.append(grid[i]); i += 1; continue
            tag = grid[i+1:j]
            if tag.startswith('NATO:'):
                code = tag.split(':',1)[1]
                if code in nato_upper:
                    result.append(nato_upper[code]); i = j+1; continue
            elif tag.startswith('nato:'):
                code = tag.split(':',1)[1]
                if code in nato_lower:
                    result.append(nato_lower[code]); i = j+1; continue
            # Not a valid NATO tag
            result.append(grid[i]); i += 1
        else:
            result.append(grid[i]); i += 1
    return ''.join(result)

