import json
import string

# NATO mapping for A-Z as specified
_NATO = [
    'ALPHA','BRAVO','CHARLIE','DELTA','ECHO','FOXTROT','GOLF','HOTEL','INDIA',
    'JULIETT','KILO','LIMA','MIKE','NOVEMBER','OSCAR','PAPA','QUEBEC','ROMEO',
    'SIERRA','TANGO','UNIFORM','VICTOR','WHISKEY','XRAY','YANKEE','ZULU'
]
_letter_to_nato = {chr(ord('A')+i): _NATO[i] for i in range(26)}
_nato_to_letter = {v: k for k, v in _letter_to_nato.items()}

_digits = ['ZERO','ONE','TWO','THREE','FOUR','FIVE','SIX','SEVEN','EIGHT','NINE']
_word_to_digit = {w: str(i) for i, w in enumerate(_digits)}
_digit_to_word = {str(i): w for i, w in enumerate(_digits)}

_ascii_letters = set(string.ascii_letters)
_digits_set = set('0123456789')

def _encode_cell(cell):
    # Only encode single-character string cells; otherwise preserve unchanged
    if not isinstance(cell, str) or len(cell) != 1:
        return cell
    c = cell
    # 1. Letters A-Z or a-z
    if c in _ascii_letters:
        word = _letter_to_nato[c.upper()]
        prefix = 'U:' if c.isupper() else 'L:'
        return prefix + word
    # 2. Digits 0-9
    if c in _digits_set:
        return 'D:' + _digit_to_word[c]
    # 3. Space
    if c == ' ':
        return 'S:SPACE'
    # 4. Printable ASCII punctuation/symbols (ASCII <=127 and not alnum or space)
    oc = ord(c)
    if oc <= 127 and not c.isalnum() and c != ' ':
        return 'P:{:02X}'.format(oc)
    # 5. Any other character
    return 'X:U+{:04X}'.format(oc)


def transform_grid(grid):
    """Encode a 3D cube (list of layers -> list of rows -> list of single-character cell strings).
    Only single-character string cells are encoded; other cells are left unchanged.
    Returns a new grid with the same nested structure.
    """
    if not isinstance(grid, list):
        raise TypeError('grid must be a list of layers')
    result = []
    for layer in grid:
        if not isinstance(layer, list):
            raise TypeError('each layer must be a list of rows')
        new_layer = []
        for row in layer:
            if not isinstance(row, list):
                raise TypeError('each row must be a list of cell-strings')
            new_row = [_encode_cell(cell) for cell in row]
            new_layer.append(new_row)
        result.append(new_layer)
    return result


def _decode_cell(s):
    # Only attempt to decode strings that match the standardized forward formats.
    if not isinstance(s, str):
        return s
    if len(s) < 2 or s[1] != ':':
        return s
    prefix = s[:2]
    rest = s[2:]
    uprest = rest.upper()
    try:
        if prefix == 'U:':
            # remainder is NATO codeword -> uppercase letter
            letter = _nato_to_letter.get(uprest)
            if letter is not None:
                return letter
            return s
        if prefix == 'L:':
            letter = _nato_to_letter.get(uprest)
            if letter is not None:
                return letter.lower()
            return s
        if prefix == 'D:':
            digit = _word_to_digit.get(uprest)
            if digit is not None:
                return digit
            return s
        if prefix == 'S:':
            # Accept "S:SPACE" or anything that begins with that
            if uprest.startswith('SPACE'):
                return ' '
            return s
        if prefix == 'P:':
            # two hex digits follow the colon; parse first two hex digits
            hexpart = rest[:2]
            if len(hexpart) == 2:
                code = int(hexpart, 16)
                return chr(code)
            return s
        if s.upper().startswith('X:U+'):
            hexpart = s[4:]
            if hexpart:
                code = int(hexpart, 16)
                return chr(code)
            return s
    except Exception:
        # On any parsing error, return original string unchanged
        return s
    return s


def inverse_transform_grid(grid):
    """Decode a grid produced by transform_grid back to the original grid.
    Strings that do not match the encoding formats are preserved unchanged.
    """
    if not isinstance(grid, list):
        raise TypeError('grid must be a list of layers')
    result = []
    for layer in grid:
        if not isinstance(layer, list):
            raise TypeError('each layer must be a list of rows')
        new_layer = []
        for row in layer:
            if not isinstance(row, list):
                raise TypeError('each row must be a list of cell-strings')
            new_row = [_decode_cell(cell) for cell in row]
            new_layer.append(new_row)
        result.append(new_layer)
    return result


