import json

# Core processing function to avoid code duplication
def _process_grid(grid, direction):
    """
    Processes a 3D grid of characters using a positional Caesar cipher.

    Args:
        grid (list[list[list[str]]]): The 3D character grid.
        direction (int): 1 for forward transform, -1 for inverse.

    Returns:
        list[list[list[str]]]: The processed 3D grid.
    """
    if not isinstance(grid, list):
        return grid

    return [
        [
            [
                _transform_char(char, z, y, x, direction)
                for x, char in enumerate(row)
            ]
            for y, row in enumerate(layer)
        ]
        for z, layer in enumerate(grid)
    ]

def _transform_char(char, z, y, x, direction):
    """Transforms a single character based on its position and direction."""
    if 'A' <= char <= 'Z':
        shift_key = z + y + x
        original_index = ord(char) - ord('A')
        # The +26 ensures the result of the modulo is always positive, which is crucial for the inverse operation.
        new_index = (original_index + direction * shift_key + 26) % 26
        return chr(new_index + ord('A'))
    return char

# 1. Forward Function
def transform_grid(grid):
    """
    Transforms a 3D cube of characters by applying a positional Caesar cipher.
    """
    return _process_grid(grid, 1)

# 2. Inverse Function
def inverse_transform_grid(grid):
    """
    Reverses the transformation to reconstruct the original 3D cube.
    """
    return _process_grid(grid, -1)

