# Helper function for character-level transformation
def _transform_char(char):
    if 'A' <= char <= 'Z':
        # Symmetrical opposite for uppercase letters (A<->Z, B<->Y, etc.)
        return chr(ord('A') + ord('Z') - ord(char))
    elif 'a' <= char <= 'z':
        # Symmetrical opposite for lowercase letters (a<->z, b<->y, etc.)
        return chr(ord('a') + ord('z') - ord(char))
    elif '0' <= char <= '9':
        # Numerical complement to 9 for digits (0<->9, 1<->8, etc.)
        return str(9 - int(char))
    else:
        # All other characters (punctuation, spaces, symbols) remain unchanged
        return char

