import json

# Helper function for character transformation
def _char_transform(char):
    if 'A' <= char <= 'Z':
        return char.lower()
    elif 'a' <= char <= 'z':
        return char.upper()
    elif '0' <= char <= '9':
        return str(9 - int(char))
    else:
        return char

# 1. Forward Function: Applies character-level transformation then row reversal.
def transform_grid(grid):
    if not isinstance(grid, list):
        raise TypeError("Input grid must be a list of strings.")

    transformed_grid = []
    for row in grid:
        if not isinstance(row, str):
            raise TypeError("Each row in the grid must be a string.")

        # Step 1: Character-level Semantic Transformation
        transformed_row_chars = [_char_transform(char) for char in row]

        # Step 2: Row Reversal
        transformed_row_str = "".join(transformed_row_chars)
        transformed_grid.append(transformed_row_str[::-1])

    return transformed_grid

# 2. Inverse Function: Applies inverse row reversal then inverse character-level transformation.
def inverse_transform_grid(grid):
    if not isinstance(grid, list):
        raise TypeError("Input grid must be a list of strings.")

    inverted_grid = []
    for row in grid:
        if not isinstance(row, str):
            raise TypeError("Each row in the grid must be a string.")

        # Step 1 (Inverse): Inverse Row Reversal (same as forward row reversal)
        reversed_row_str = row[::-1]

        # Step 2 (Inverse): Inverse Character-level Semantic Transformation (same as forward char transformation)
        inverted_row_chars = [_char_transform(char) for char in reversed_row_str]
        inverted_grid.append("".join(inverted_row_chars))

    return inverted_grid

