import json

# Helper function for character-level Atbash transformation
def _atbash_char(char):
    if 'A' <= char <= 'Z':
        # Calculate position (0-25 for A-Z)
        pos = ord(char) - ord('A')
        # Apply Atbash transformation (25 - pos)
        transformed_pos = 25 - pos
        # Convert back to character
        return chr(ord('A') + transformed_pos)
    else:
        # Other characters remain unchanged
        return char

# Helper function for string-level transformation
def _transform_string(s):
    # Ensure input is a string
    if not isinstance(s, str):
        raise TypeError(f"Expected a string, got {type(s)}")
    return "".join([_atbash_char(c) for c in s])

# 1. Forward Function: Transforms a 3D grid of strings
def transform_grid(grid):
    if not isinstance(grid, list):
        raise TypeError("Input grid must be a list.")

    transformed_grid = []
    for z_slice in grid:
        if not isinstance(z_slice, list):
            raise TypeError("Each z_slice in grid must be a list.")

        transformed_z_slice = []
        for y_row in z_slice:
            if not isinstance(y_row, list):
                raise TypeError("Each y_row in z_slice must be a list.")

            transformed_y_row = []
            for x_string in y_row:
                # _transform_string handles type checking for x_string
                transformed_y_row.append(_transform_string(x_string))
            transformed_z_slice.append(transformed_y_row)
        transformed_grid.append(transformed_z_slice)
    return transformed_grid

# 2. Inverse Function: Reverses the transformation
# As per the rule, Atbash is its own inverse, so the inverse function is identical.
def inverse_transform_grid(grid):
    # The inverse transformation is identical to the forward transformation
    # because Atbash is an involutory function (applying it twice returns the original).
    return transform_grid(grid)

