import json

# 1. Forward Function
def transform_grid(grid):
    D = len(grid)
    if D == 0:
        return []
    # ensure cube validity
    for x in grid:
        if len(x) != D:
            raise ValueError('Grid is not cubic')
        for row in x:
            if len(row) != D:
                raise ValueError('Grid is not cubic')
    # Step 1: Coordinate-Based Caesar Shift
    S = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for x in range(D):
        for y in range(D):
            for z in range(D):
                s = (3*x + 5*y + 7*z) % 256
                v = ord(grid[x][y][z])
                S[x][y][z] = chr((v + s) % 256)
    # Step 2: Conditional Layer Transform
    R = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for z in range(D):
        if z % 2 == 0:
            for x in range(D):
                for y in range(D):
                    R[x][y][z] = S[D-1-x][D-1-y][z]
        else:
            for x in range(D):
                for y in range(D):
                    R[x][y][z] = S[y][x][z]
    # Step 3: Slice-Order Reversal
    E = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for x in range(D):
        for y in range(D):
            for z in range(D):
                E[x][y][z] = R[x][y][D-1-z]
    return E

# 2. Inverse Function
def inverse_transform_grid(grid):
    D = len(grid)
    if D == 0:
        return []
    for x in grid:
        if len(x) != D:
            raise ValueError('Grid is not cubic')
        for row in x:
            if len(row) != D:
                raise ValueError('Grid is not cubic')
    # Step 1: Reverse Slice Order
    U = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for x in range(D):
        for y in range(D):
            for z in range(D):
                U[x][y][z] = grid[x][y][D-1-z]
    # Step 2: Inverse Layer Transform
    Sp = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for z in range(D):
        if z % 2 == 0:
            for x in range(D):
                for y in range(D):
                    Sp[x][y][z] = U[D-1-x][D-1-y][z]
        else:
            for x in range(D):
                for y in range(D):
                    Sp[x][y][z] = U[y][x][z]
    # Step 3: Inverse Coordinate-Based Caesar
    C = [[[None for z in range(D)] for y in range(D)] for x in range(D)]
    for x in range(D):
        for y in range(D):
            for z in range(D):
                s = (3*x + 5*y + 7*z) % 256
                w = ord(Sp[x][y][z])
                C[x][y][z] = chr((w - s) % 256)
    return C

