import json, math

# 1. Forward Function
def transform_grid(grid):
    # Operate on a shallow copy and return a new list
    grid = list(grid)
    n = len(grid)
    if n <= 2:
        return grid.copy()
    # choose smallest k in [2, n-1] with gcd(k,n) == 1
    for k in range(2, n):
        if math.gcd(k, n) == 1:
            break
    t = [None] * n
    for i, val in enumerate(grid):
        j = (i * k) % n
        t[j] = val
    return t

# 2. Inverse Function
def inverse_transform_grid(grid):
    grid = list(grid)
    n = len(grid)
    if n <= 2:
        return grid.copy()
    # recompute the same deterministic k
    for k in range(2, n):
        if math.gcd(k, n) == 1:
            break
    # extended Euclidean algorithm to find modular inverse of k mod n
    def egcd(a, b):
        if b == 0:
            return (a, 1, 0)
        g, x1, y1 = egcd(b, a % b)
        return (g, y1, x1 - (a // b) * y1)
    g, x, y = egcd(k, n)
    k_inv = x % n
    s = [None] * n
    for j, val in enumerate(grid):
        i = (j * k_inv) % n
        s[i] = val
    return s

