import json

def transform_grid(grid):
    """
    Transforms a 3D grid by swapping characters between even and odd parity locations.
    """
    if not grid or not grid[0] or not grid[0][0]:
        return grid

    depth = len(grid)
    height = len(grid[0])
    width = len(grid[0][0])

    list_even = []
    list_odd = []

    # 1. Partition characters into two lists based on coordinate sum parity
    for z in range(depth):
        for y in range(height):
            for x in range(width):
                if (x + y + z) % 2 == 0:
                    list_even.append(grid[z][y][x])
                else:
                    list_odd.append(grid[z][y][x])

    # Prepare iterators for filling the new grid
    iter_even = iter(list_even)
    iter_odd = iter(list_odd)

    # Create a new grid of the same dimensions
    result_grid = [[[None for _ in range(width)] for _ in range(height)] for _ in range(depth)]

    # 2. Construct the output grid by swapping the lists
    for z in range(depth):
        for y in range(height):
            for x in range(width):
                if (x + y + z) % 2 == 0:
                    # Even-sum output locations get characters from the odd list
                    result_grid[z][y][x] = next(iter_odd)
                else:
                    # Odd-sum output locations get characters from the even list
                    result_grid[z][y][x] = next(iter_even)

    return result_grid

def inverse_transform_grid(grid):
    """
    The inverse transformation is identical to the forward transformation.
    """
    return transform_grid(grid)

